// =============================================================================
// Libsodium test vector infrastructure
//
// Vectors generated by PyNaCl (libsodium) — see testdata/generate_vectors.py.
// Every deterministic primitive is verified byte-for-byte against libsodium.
// Every encryption vector is generated by Python and decrypted by Go.
// =============================================================================

type testVectors struct {
	SeedKeypairs      []seedKeypairVector  `json:"seed_keypairs"`
	Blake2bDigests    []blake2bVector      `json:"blake2b_digests"`
	SessionKeys       sessionKeyVector     `json:"session_keys"`
	EncryptRaw        []encryptRawVector   `json:"encrypt_raw"`
	AsymmetricEncrypt []asymmetricVector   `json:"asymmetric_encrypt"`
	XORReconstruct    []xorVector          `json:"xor_reconstruct"`
}

type seedKeypairVector struct {
	Seed       string `json:"seed"`
	PublicKey  string `json:"public_key"`
	PrivateKey string `json:"private_key"`
}

type blake2bVector struct {
	Input  string `json:"input"`
	Salt   string `json:"salt"`
	Digest string `json:"digest"`
}

type sessionKeyVector struct {
	SeedA       string `json:"seed_a"`
	SeedB       string `json:"seed_b"`
	PublicKeyA  string `json:"public_key_a"`
	PrivateKeyA string `json:"private_key_a"`
	PublicKeyB  string `json:"public_key_b"`
	PrivateKeyB string `json:"private_key_b"`
	ClientRx    string `json:"client_rx"`
	ClientTx    string `json:"client_tx"`
	ServerRx    string `json:"server_rx"`
	ServerTx    string `json:"server_tx"`
}

type encryptRawVector struct {
	Plaintext           string `json:"plaintext"`
	Key                 string `json:"key"`
	CiphertextWithNonce string `json:"ciphertext_with_nonce"`
}

type asymmetricVector struct {
	Plaintext           string `json:"plaintext"`
	RecipientSeed       string `json:"recipient_seed"`
	RecipientPublicKey  string `json:"recipient_public_key"`
	RecipientPrivateKey string `json:"recipient_private_key"`
	Ciphertext          string `json:"ciphertext"`
}

type xorVector struct {
	Shares   []string `json:"shares"`
	Expected string   `json:"expected"`
}

func loadVectors(t *testing.T) testVectors {
	t.Helper()
	_, filename, _, _ := runtime.Caller(0)
	path := filepath.Join(filepath.Dir(filename), "testdata", "test_vectors.json")

	data, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("Failed to read test vectors: %v", err)
	}

	var v testVectors
	if err := json.Unmarshal(data, &v); err != nil {
		t.Fatalf("Failed to parse test vectors: %v", err)
	}
	return v
}

// =============================================================================
// XORBytes
// =============================================================================

func TestXORBytes(t *testing.T) {
	tests := []struct {
		name     string
		a        []byte
		b        []byte
		expected []byte
		wantErr  bool
	}{
		{
			name:     "basic XOR",
			a:        []byte{0x00, 0xFF, 0xAA, 0x55},
			b:        []byte{0xFF, 0xFF, 0x55, 0xAA},
			expected: []byte{0xFF, 0x00, 0xFF, 0xFF},
		},
		{
			name:     "XOR with zeros is identity",
			a:        []byte{0x12, 0x34, 0x56, 0x78},
			b:        []byte{0x00, 0x00, 0x00, 0x00},
			expected: []byte{0x12, 0x34, 0x56, 0x78},
		},
		{
			name:     "XOR with self is zero",
			a:        []byte{0xDE, 0xAD, 0xBE, 0xEF},
			b:        []byte{0xDE, 0xAD, 0xBE, 0xEF},
			expected: []byte{0x00, 0x00, 0x00, 0x00},
		},
		{
			name:     "empty slices",
			a:        []byte{},
			b:        []byte{},
			expected: []byte{},
		},
		{
			name:    "length mismatch",
			a:       []byte{0x00, 0xFF},
			b:       []byte{0xFF},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result, err := XORBytes(tt.a, tt.b)
			if tt.wantErr {
				if err == nil {
					t.Error("expected error, got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if !bytes.Equal(result, tt.expected) {
				t.Errorf("got %x, want %x", result, tt.expected)
			}
		})
	}
}

func TestXORBytesReversibility(t *testing.T) {
	a := make([]byte, 32)
	b := make([]byte, 32)
	rand.Read(a)
	rand.Read(b)

	xored, err := XORBytes(a, b)
	if err != nil {
		t.Fatalf("XORBytes() error: %v", err)
	}

	recovered, err := XORBytes(xored, b)
	if err != nil {
		t.Fatalf("XORBytes() error: %v", err)
	}

	if !bytes.Equal(recovered, a) {
		t.Errorf("(a ^ b) ^ b != a: got %x, want %x", recovered, a)
	}
}

// =============================================================================
// ReconstructSecret
// =============================================================================

func TestReconstructSecret(t *testing.T) {
	t.Run("error handling", func(t *testing.T) {
		cases := []struct {
			name   string
			share1 string
			share2 string
		}{
			{"invalid hex share1", "xyz", "cafe"},
			{"invalid hex share2", "cafe", "xyz"},
			{"length mismatch", "deadbeef", "cafe"},
		}
		for _, tc := range cases {
			t.Run(tc.name, func(t *testing.T) {
				_, err := ReconstructSecret(tc.share1, tc.share2)
				if err == nil {
					t.Error("expected error, got nil")
				}
			})
		}
	})

	// Verify against libsodium vectors
	t.Run("libsodium vectors", func(t *testing.T) {
		v := loadVectors(t)
		for _, tc := range v.XORReconstruct {
			t.Run(tc.Shares[0][:16]+"...", func(t *testing.T) {
				result, err := ReconstructSecret(tc.Shares[0], tc.Shares[1])
				if err != nil {
					t.Fatalf("error: %v", err)
				}
				if result != tc.Expected {
					t.Errorf("mismatch\n  go:        %s\n  libsodium: %s", result, tc.Expected)
				}
			})
		}
	})
}

// =============================================================================
// Blake2bDigest
// =============================================================================

func TestBlake2bDigest(t *testing.T) {
	// Go-only known answer tests (unkeyed BLAKE2b-256)
	t.Run("unkeyed known answers", func(t *testing.T) {
		tests := []struct {
			input    string
			expected string
		}{
			{"", "0e5751c026e543b2e8ab2eb06099daa1d1e5df47778f7787faab45cdf12fe3a8"},
			{"hello world", "256c83b297114d201b30179f3f0ef0cace9783622da5974326b436178aeef610"},
		}
		for _, tt := range tests {
			name := tt.input
			if name == "" {
				name = "(empty)"
			}
			t.Run(name, func(t *testing.T) {
				result, err := Blake2bDigest(tt.input, "")
				if err != nil {
					t.Fatalf("error: %v", err)
				}
				if result != tt.expected {
					t.Errorf("got %s, want %s", result, tt.expected)
				}
			})
		}
	})

	// Verify against libsodium vectors (keyed + unkeyed, unicode, long input)
	t.Run("libsodium vectors", func(t *testing.T) {
		v := loadVectors(t)
		for _, tc := range v.Blake2bDigests {
			name := tc.Input
			if len(name) > 30 {
				name = name[:30] + "..."
			}
			if name == "" {
				name = "(empty)"
			}
			t.Run(name, func(t *testing.T) {
				digest, err := Blake2bDigest(tc.Input, tc.Salt)
				if err != nil {
					t.Fatalf("error: %v", err)
				}
				if digest != tc.Digest {
					t.Errorf("mismatch (salt=%q)\n  go:        %s\n  libsodium: %s", tc.Salt, digest, tc.Digest)
				}
			})
		}
	})

	t.Run("salt changes output", func(t *testing.T) {
		input := "test data"
		h1, _ := Blake2bDigest(input, "")
		h2, _ := Blake2bDigest(input, "salt1")
		h3, _ := Blake2bDigest(input, "salt2")

		if h1 == h2 {
			t.Error("keyed hash should differ from unkeyed")
		}
		if h2 == h3 {
			t.Error("different salts should produce different hashes")
		}
	})

	t.Run("deterministic", func(t *testing.T) {
		h1, _ := Blake2bDigest("deterministic test", "my-salt")
		h2, _ := Blake2bDigest("deterministic test", "my-salt")
		if h1 != h2 {
			t.Errorf("not deterministic: %s != %s", h1, h2)
		}
	})
}

