func BenchmarkEncryptRaw(b *testing.B) {
	key := randomKeyB()
	pt := strings.Repeat("a", 1024)
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		EncryptRaw(pt, key)
	}
}

func BenchmarkDecryptRaw(b *testing.B) {
	key := randomKeyB()
	ct, _ := EncryptRaw(strings.Repeat("a", 1024), key)
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		DecryptRaw(ct, key)
	}
}

func BenchmarkBlake2bDigest(b *testing.B) {
	input := strings.Repeat("a", 1024)
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		Blake2bDigest(input, "benchmark-salt")
	}
}

func BenchmarkSessionKeys(b *testing.B) {
	clientKP, _ := RandomKeyPair()
	serverKP, _ := RandomKeyPair()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		ClientSessionKeys(clientKP, serverKP.PublicKey[:])
	}
}

func BenchmarkEncryptAsymmetric(b *testing.B) {
	recipientKP, _ := RandomKeyPair()
	pubHex := hex.EncodeToString(recipientKP.PublicKey[:])
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		EncryptAsymmetric("benchmark secret message", pubHex)
	}
}

// =============================================================================
// Helpers
// =============================================================================

func randomKey() [32]byte {
	var k [32]byte
	rand.Read(k[:])
	return k
}

func randomKeyB() [32]byte {
	var k [32]byte
	rand.Read(k[:])
	return k
}

func mustKeyFromHex(t *testing.T, h string) [32]byte {
	t.Helper()
	b, err := hex.DecodeString(h)
	if err != nil {
		t.Fatalf("invalid hex key: %v", err)
	}
	var k [32]byte
	copy(k[:], b)
	return k
}

func mustKeyPairFromHex(t *testing.T, pubHex, privHex string) KeyPair {
	t.Helper()
	pub, _ := hex.DecodeString(pubHex)
	priv, _ := hex.DecodeString(privHex)
	var kp KeyPair
	copy(kp.PublicKey[:], pub)
	copy(kp.SecretKey[:], priv)
	return kp
}
